function getInput(callback){
	process.stdin.resume();
	process.stdin.setEncoding('utf8');
	process.stdin.on('data', function (str) {
		if(str != '\n'){
			callback(str.trim());
			process.stdin.pause();
		}
	});
	process.stdin.on('end', function () {
		process.stdout.write('end');
	});
}
module.exports = getInput;